package com.example.appwatch.ui.screensimport android.content.Contextimport androidx.compose.foundation.backgroundimport androidx.compose.foundation.clickableimport androidx.compose.foundation.layout.*import androidx.compose.foundation.lazy.LazyColumnimport androidx.compose.foundation.shape.CircleShapeimport androidx.compose.foundation.shape.RoundedCornerShapeimport androidx.compose.material.icons.Iconsimport androidx.compose.material.icons.filled.*import androidx.compose.material3.*import androidx.compose.runtime.*import androidx.compose.ui.Alignmentimport androidx.compose.ui.Modifierimport androidx.compose.ui.draw.clipimport androidx.compose.ui.graphics.Colorimport androidx.compose.ui.graphics.vector.ImageVectorimport androidx.compose.ui.platform.LocalContextimport androidx.compose.ui.res.stringResourceimport androidx.compose.ui.text.font.FontWeightimport androidx.compose.ui.text.style.TextAlignimport androidx.compose.ui.text.style.TextOverflowimport androidx.compose.ui.unit.dpimport androidx.compose.ui.unit.spimport androidx.hilt.navigation.compose.hiltViewModelimport androidx.navigation.NavControllerimport com.example.appwatch.Rimport com.example.appwatch.domain.model.DashboardSummaryimport com.example.appwatch.ui.viewModels.DashboardViewModelimport com.example.appwatch.ui.ScreenComponents.NeedsAttentionSectionimport com.example.appwatch.ui.ScreenComponents.RecentActivitySectionimport com.example.appwatch.ui.components.DashboardInitialLoaderimport com.example.appwatch.ui.components.DashboardLoaderimport com.example.appwatch.ui.theme.*import kotlinx.coroutines.delayimport java.text.SimpleDateFormatimport java.util.Calendarimport java.util.Locale@Composablefun DashboardScreen(    navController: NavController,    viewModel: DashboardViewModel = hiltViewModel()) {    val context = LocalContext.current    val uiState by viewModel.uiState.collectAsState()    val totalUnlocks = viewModel.totalUnlocksToday.collectAsState().value    val totalNotifications = viewModel.totalNotificationsToday.collectAsState().value    val dataUsageBytes = viewModel.totalDataUsageBytes.collectAsState().value    val formattedDataUsage = viewModel.formatDataUsage(dataUsageBytes)    val patch = viewModel.systemUpdate.collectAsState().value    val sharedPref = remember {        context.getSharedPreferences("app_watch_prefs", Context.MODE_PRIVATE)    }    val isFirstRun = remember {        sharedPref.getBoolean("is_first_run", true)    }    when {        isFirstRun && uiState.isFirstSync -> {            DashboardInitialLoader()        }        // Room ka data aate hi turant dikhao (Zero Second wait!)        uiState.summary != null && uiState.summary!!.totalApps > 0 -> {            LaunchedEffect(Unit) {                if (isFirstRun) {                    sharedPref.edit().putBoolean("is_first_run", false).apply()                }            }            DashboardContent(                navController = navController,                summary = uiState.summary!!,                totalUnlocks = totalUnlocks,                totalNotifications = totalNotifications,                formattedDataUsage = formattedDataUsage,                patch = patch,                isRefreshing = uiState.isRefreshing,                viewModel = viewModel            )        }        else->{            DashboardLoader()        }    }}@OptIn(ExperimentalMaterial3Api::class)@Composablefun DashboardContent(    navController: NavController,    summary: DashboardSummary,    totalUnlocks: Int,    totalNotifications: Int,    formattedDataUsage: String,    patch: String,    isRefreshing: Boolean,    viewModel: DashboardViewModel = hiltViewModel()) {    val calendar = Calendar.getInstance()    val dateStr = SimpleDateFormat("dd MMM YYYY", Locale.getDefault()).format(calendar.time)    val dayStr = SimpleDateFormat("EEEE", Locale.getDefault()).format(calendar.time)    val REFRESH_INTERVAL = 5 * 60 * 1000L    LaunchedEffect(Unit) {        while (true) {            delay(REFRESH_INTERVAL)            viewModel.refreshInBackground()        }    }    Scaffold(        containerColor = BackgroundLight,    ) { padding ->        Column(            modifier = Modifier                .fillMaxSize()                .padding(bottom = padding.calculateBottomPadding())                .statusBarsPadding()        ) {            if (isRefreshing) {                DashboardSyncingBar()            }            LazyColumn(                modifier = Modifier.fillMaxSize(),                contentPadding = PaddingValues(                    start = 16.dp,                    end = 16.dp,                    top = 16.dp,                    bottom = 24.dp                ),                verticalArrangement = Arrangement.spacedBy(20.dp)            ) {                item {                    Column(                        modifier = Modifier.fillMaxWidth().padding(bottom = 8.dp)                    ) {                        Row(                            modifier = Modifier.fillMaxWidth(),                            horizontalArrangement = Arrangement.SpaceBetween,                            verticalAlignment = Alignment.CenterVertically                        ) {                            Row(                                verticalAlignment = Alignment.CenterVertically,                                modifier = Modifier.weight(1f)                            ) {                                Icon(                                    imageVector = Icons.Default.Shield,                                    contentDescription = null,                                    tint = Indigo600,                                    modifier = Modifier.size(28.dp)                                )                                Spacer(Modifier.width(8.dp))                                Text(                                    text = stringResource(R.string.app_name),                                    fontWeight = FontWeight.ExtraBold,                                    fontSize = 20.sp,                                    maxLines = 1,                                    overflow = TextOverflow.Clip                                )                            }                            IconButton(                                onClick = { navController.navigate("settings") },                                modifier = Modifier                                    .clip(CircleShape)                                    .background(SurfaceVariantSoft)                                    .size(40.dp)                            ) {                                Icon(                                    Icons.Default.Settings,                                    contentDescription = stringResource(R.string.settings_title),                                    tint = TextPrimary,                                    modifier = Modifier.size(22.dp)                                )                            }                        }                        Spacer(modifier = Modifier.height(8.dp))                        Column {                            Text(                                text = dateStr,                                style = MaterialTheme.typography.displaySmall,                                fontWeight = FontWeight.Black,                                color = TextPrimary,                                maxLines = 1,                                overflow = TextOverflow.Clip                            )                            Text(                                text = dayStr,                                style = MaterialTheme.typography.titleMedium,                                fontWeight = FontWeight.Bold,                                color = TextSecondary,                                maxLines = 1,                                overflow = TextOverflow.Clip                            )                        }                    }                }                // ── 1. Overview ───────────────────────────────────────────────────                item {                    Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {                        Text(                            text = stringResource(R.string.dash_header_overview),                            style = MaterialTheme.typography.titleLarge,                            fontWeight = FontWeight.Bold,                            color = TextPrimary,                            maxLines = 1,                            overflow = TextOverflow.Ellipsis                        )                        Row(                            modifier = Modifier.fillMaxWidth(),                            horizontalArrangement = Arrangement.spacedBy(12.dp)                        ) {                            StatCard(                                label = stringResource(R.string.dash_stat_apps),                                value = summary.totalApps.toString(),                                icon = Icons.Default.Apps,                                color = StatApps,                                modifier = Modifier                                    .weight(1f)                                    .clickable { navController.navigate("app_list") }                            )                            StatCard(                                label = stringResource(R.string.dash_stat_storage),                                value = summary.usedStorage,                                subValue = summary.totalStorage,                                icon = Icons.Default.SdStorage,                                color = StatStorage,                                modifier = Modifier                                    .weight(1f)                                    .clickable { navController.navigate("storage_detail") }                            )                            StatCard(                                label = stringResource(R.string.dash_stat_update),                                value = patch,                                icon = Icons.Default.TrendingUp,                                color = StatSecurity,                                modifier = Modifier                                    .weight(1f)                                    .clickable { }                            )                        }                    }                }                // ── 2. Today's Activity ───────────────────────────────────────────                item {                    Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {                        Text(                            text = stringResource(R.string.dash_header_today),                            style = MaterialTheme.typography.titleLarge,                            fontWeight = FontWeight.Bold,                            color = TextPrimary,                            maxLines = 1,                            overflow = TextOverflow.Ellipsis                        )                        Row(                            modifier = Modifier.fillMaxWidth(),                            horizontalArrangement = Arrangement.spacedBy(12.dp)                        ) {                            InsightCard(                                title = stringResource(R.string.dash_stat_unlocks),                                count = stringResource(R.string.dash_val_unlocks, totalUnlocks),                                icon = Icons.Default.LockOpen,                                color = StatUnlocks,                                modifier = Modifier.weight(1f),                                isUpdating = isRefreshing,                                onClick = {}                            )                            InsightCard(                                title = stringResource(R.string.dash_stat_notifs),                                count = stringResource(                                    R.string.dash_val_notifs,                                    totalNotifications                                ),                                icon = Icons.Default.Notifications,                                color = StatNotifs,                                modifier = Modifier.weight(1f),                                isUpdating = isRefreshing,                                onClick = { navController.navigate("notification_screen") }                            )                        }                        Row(                            modifier = Modifier.fillMaxWidth(),                            horizontalArrangement = Arrangement.spacedBy(12.dp)                        ) {                            InsightCard(                                title = stringResource(R.string.dash_stat_screen_time),                                count = summary.totalScreenTime,                                icon = Icons.Default.TrendingUp,                                color = StatScreen,                                modifier = Modifier.weight(1f),                                isUpdating = isRefreshing,                                onClick = { navController.navigate("usage_stats") }                            )                            InsightCard(                                title = stringResource(R.string.dash_stat_data_usage),                                count = formattedDataUsage,                                icon = Icons.Default.SwapVert,                                color = StatData,                                modifier = Modifier.weight(1f),                                isUpdating = isRefreshing,                                onClick = { navController.navigate("data_usage") }                            )                        }                    }                }                item {                    RecentActivitySection(                        recentItems = summary.recentActivity,                        isUpdating = isRefreshing,                        viewModel = viewModel,                        onNavigateToEventScreen = { type ->                            navController.navigate("recentEventScreen/$type")                        }                    )                }                item {                    NeedsAttentionSection(                        attentionItems = summary.attentionItems,                        isUpdating = isRefreshing,                        onItemClick = { type ->                            navController.navigate("needs_attention/$type")                        }                    )                }                // ── 4. Privacy Insights ───────────────────────────────────────────                item {                    Column(verticalArrangement = Arrangement.spacedBy(12.dp)) {                        Row(                            modifier = Modifier.fillMaxWidth(),                            verticalAlignment = Alignment.CenterVertically,                            horizontalArrangement = Arrangement.SpaceBetween                        ) {                            Text(                                text = stringResource(R.string.dash_header_privacy),                                style = MaterialTheme.typography.titleLarge,                                fontWeight = FontWeight.Bold,                                color = TextPrimary,                                modifier = Modifier.weight(1f),                                maxLines = 1,                                overflow = TextOverflow.Ellipsis                            )                            if (isRefreshing) {                                Row(verticalAlignment = Alignment.CenterVertically) {                                    Text(                                        text = stringResource(R.string.dash_status_updating),                                        style = MaterialTheme.typography.labelSmall,                                        color = MaterialTheme.colorScheme.primary.copy(alpha = 0.7f),                                        maxLines = 1,                                        overflow = TextOverflow.Clip                                    )                                    Spacer(Modifier.width(8.dp))                                    CircularProgressIndicator(                                        modifier = Modifier.size(14.dp),                                        strokeWidth = 2.dp,                                        color = MaterialTheme.colorScheme.primary                                    )                                }                            }                        }                        Row(                            modifier = Modifier.fillMaxWidth(),                            horizontalArrangement = Arrangement.spacedBy(12.dp)                        ) {                            InsightCard(                                title = stringResource(R.string.dash_insight_location),                                count = stringResource(                                    R.string.dash_val_apps_count,                                    summary.locationAppsCount                                ),                                icon = Icons.Default.LocationOn,                                color = ColorLocation,                                modifier = Modifier.weight(1f),                                isUpdating = isRefreshing,                                onClick = {                                    if (!isRefreshing) {                                        navController.navigate("apps_with_permission/LOCATION")                                    }                                }                            )                            InsightCard(                                title = stringResource(R.string.dash_insight_camera),                                count = stringResource(                                    R.string.dash_val_apps_count,                                    summary.cameraAppsCount                                ),                                icon = Icons.Default.Camera,                                color = ColorCamera,                                modifier = Modifier.weight(1f),                                isUpdating = isRefreshing,                                onClick = {                                    if (!isRefreshing) {                                        navController.navigate("apps_with_permission/CAMERA")                                    }                                }                            )                        }                        Row(                            modifier = Modifier.fillMaxWidth(),                            horizontalArrangement = Arrangement.spacedBy(12.dp)                        ) {                            InsightCard(                                title = stringResource(R.string.dash_insight_mic),                                count = stringResource(                                    R.string.dash_val_apps_count,                                    summary.micAppsCount                                ),                                icon = Icons.Default.Mic,                                color = ColorMic,                                modifier = Modifier.weight(1f),                                isUpdating = isRefreshing,                                onClick = {                                    if (!isRefreshing) {                                        navController.navigate("apps_with_permission/RECORD_AUDIO")                                    }                                }                            )                            InsightCard(                                title = stringResource(R.string.dash_insight_phone),                                count = stringResource(                                    R.string.dash_val_apps_count,                                    summary.phoneAppsCount                                ),                                icon = Icons.Default.Phone,                                color = ColorPhone,                                modifier = Modifier.weight(1f),                                isUpdating = isRefreshing,                                onClick = {                                    if (!isRefreshing) {                                        navController.navigate("apps_with_permission/CALL_LOG")                                    }                                }                            )                        }                        Row(                            modifier = Modifier.fillMaxWidth(),                            horizontalArrangement = Arrangement.spacedBy(12.dp)                        ) {                            InsightCard(                                title = stringResource(R.string.dash_insight_contacts),                                count = stringResource(                                    R.string.dash_val_apps_count,                                    summary.contactAppsCount                                ),                                icon = Icons.Default.Contacts,                                color = ColorContacts,                                modifier = Modifier.weight(1f),                                isUpdating = isRefreshing,                                onClick = {                                    if (!isRefreshing) {                                        navController.navigate("apps_with_permission/CONTACTS")                                    }                                }                            )                            InsightCard(                                title = stringResource(R.string.dash_insight_sms),                                count = stringResource(                                    R.string.dash_val_apps_count,                                    summary.SmsAppsCount                                ),                                icon = Icons.Default.Sms,                                color = ColorSms,                                modifier = Modifier.weight(1f),                                isUpdating = isRefreshing,                                onClick = {                                    if (!isRefreshing) {                                        navController.navigate("apps_with_permission/SMS")                                    }                                }                            )                        }                    }                }            }        }    }}// ─── StatCard ─────────────────────────────────────────────────────────────────@Composablefun StatCard(    label: String,    value: String,    subValue: String = "",    icon: ImageVector,    color: Color,    modifier: Modifier = Modifier) {    ElevatedCard(        modifier = modifier.fillMaxHeight(),        colors = CardDefaults.elevatedCardColors(            containerColor = SurfaceWhite        ),        elevation = CardDefaults.elevatedCardElevation(defaultElevation = 2.dp),        shape = RoundedCornerShape(16.dp)    ) {        Column(            modifier = Modifier                .padding(12.dp)                .fillMaxWidth(),            horizontalAlignment = Alignment.CenterHorizontally,            verticalArrangement = Arrangement.Center        ) {            Box(                modifier = Modifier                    .size(42.dp)                    .background(color.copy(alpha = 0.12f), CircleShape),                contentAlignment = Alignment.Center            ) {                Icon(                    icon,                    contentDescription = null,                    modifier = Modifier.size(20.dp),                    tint = color                )            }            Spacer(modifier = Modifier.height(12.dp))            Text(                text = value,                style = MaterialTheme.typography.titleLarge,                fontWeight = FontWeight.Bold,                color = TextPrimary,                textAlign = TextAlign.Center,                maxLines = 1,                overflow = TextOverflow.Ellipsis            )            Box(modifier = Modifier.height(16.dp), contentAlignment = Alignment.Center) {                if (subValue.isNotEmpty()) {                    Text(                        text = stringResource(R.string.dash_label_of_total, subValue),                        style = MaterialTheme.typography.labelSmall,                        color = TextSecondary,                        textAlign = TextAlign.Center,                        maxLines = 1,                        overflow = TextOverflow.Clip                    )                }            }            Spacer(modifier = Modifier.height(4.dp))            Text(                text = label,                style = MaterialTheme.typography.bodySmall,                color = TextSecondary,                fontWeight = FontWeight.Medium,                textAlign = TextAlign.Center,                maxLines = 1,                overflow = TextOverflow.Clip            )        }    }}// ─── InsightCard ──────────────────────────────────────────────────────────────@Composablefun InsightCard(    title: String,    count: String,    icon: ImageVector,    color: Color,    modifier: Modifier,    isUpdating: Boolean,    onClick: () -> Unit) {    Card(        modifier = modifier,        onClick = onClick,        colors = CardDefaults.cardColors(            containerColor = color.copy(alpha = 0.09f)        ),        shape = RoundedCornerShape(16.dp),        elevation = CardDefaults.cardElevation(defaultElevation = 0.dp)    ) {        Column(modifier = Modifier.padding(16.dp)) {            Box(                modifier = Modifier                    .size(36.dp)                    .background(color.copy(alpha = 0.15f), CircleShape),                contentAlignment = Alignment.Center            ) {                Icon(                    icon,                    contentDescription = null,                    modifier = Modifier.size(20.dp),                    tint = color                )            }            Spacer(modifier = Modifier.height(10.dp))            Text(                text = title,                style = MaterialTheme.typography.titleSmall,                fontWeight = FontWeight.SemiBold,                color = TextPrimary,                maxLines = 1,                overflow = TextOverflow.Ellipsis            )            Text(                text = count,                style = MaterialTheme.typography.bodyMedium,                color = color,                fontWeight = FontWeight.Bold,                maxLines = 1,                overflow = TextOverflow.Clip            )        }    }}@Composablefun DashboardSyncingBar(modifier: Modifier = Modifier) {    Surface(        modifier = modifier            .fillMaxWidth()            .statusBarsPadding(),        color = BackgroundLight    ) {        Column(            modifier = Modifier.fillMaxWidth().padding(top=16.dp)        ) {            LinearProgressIndicator(                modifier = Modifier                    .fillMaxWidth()                    .height(4.dp),                color = Indigo600,                trackColor = Indigo100            )            Spacer(modifier=Modifier.height(4.dp))            Text(                text = stringResource(R.string.dash_syncing),                style = MaterialTheme.typography.labelSmall,                color = Indigo500.copy(alpha = 0.7f),                fontSize = 13.sp,                fontWeight = FontWeight.Medium,                modifier = Modifier.padding(start=16.dp),                maxLines = 1,                overflow = TextOverflow.Clip            )            Spacer(modifier=Modifier.height(4.dp))        }    }}